code = """import json
import pandas as pd
import re

businesses = locals()['var_functions.query_db:2']
reviews_path = locals()['var_functions.query_db:4']

with open(reviews_path, 'r') as f:
    reviews = json.load(f)

df_b = pd.DataFrame(businesses)
df_r = pd.DataFrame(reviews)

df_b['id_num'] = df_b['business_id'].str.replace('businessid_', '').astype(int)
df_r['id_num'] = df_r['business_ref'].str.replace('businessref_', '').astype(int)

categories = []
for desc in df_b['description']:
    if pd.notna(desc):
        parts = desc.split('services in ')
        if len(parts) > 1:
            cats = parts[1].split('.')[0]
            for cat in cats.split(','):
                cat = cat.strip()
                if cat and cat not in ['Local Services', 'and']:
                    if ' and ' in cat:
                        categories.extend([c.strip() for c in cat.split(' and ')])
                    else:
                        categories.append(cat)

from collections import Counter
cat_counts = Counter(categories)
top_cat = cat_counts.most_common(1)[0][0]

cat_business_ids = []
for idx, row in df_b.iterrows():
    if pd.notna(row['description']) and top_cat in row['description']:
        cat_business_ids.append(row['id_num'])

ratings = df_r[df_r['id_num'].isin(cat_business_ids)]['rating']
avg_rating = ratings.astype(float).mean() if not ratings.empty else 0

result = {
    'category': top_cat,
    'business_count': len(cat_business_ids),
    'total_reviews': len(ratings),
    'average_rating': round(avg_rating, 2)
}

print('__RESULT__:')
print(json.dumps(result))"""

